var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"근데 당신도 움직일 수 없다면서요.","JPN":"でも、あなたは動けないんでしょう？","ENG":"But you said you can't move either.","TWN":"可是你不是也不能行動嗎？"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"저밖에 없는데 계획이 무슨 소용이에요?","JPN":"私しかいないのに、計画も何もないじゃないですか。","ENG":"If I'm the only one left, what good is a plan?","TWN":"只有我一個人，計畫有什麼用呢？"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"그러니까 자매님이 움직여야지.","JPN":"だから、あなたが行かないと。","ENG":"That's why you need to act.","TWN":"所以，你得行動起來。"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L7_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"읏…… 아까도 말씀드렸잖아요!","JPN":"うっ……さっきも言ったじゃないですか！","ENG":"Ngh... I already told you!","TWN":"呃……我剛才已經告訴過你了！"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"저 안에서 감염자는 힘을 쓸 수 없단 말이에요!","JPN":"あの邸宅の中で感染者は力が使えないって！","ENG":"Afflicted people can't fight in there!","TWN":"在那裡面，感染者無法使用力量！"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"영지 주인은 또 얼마나 강한데요!","JPN":"それに、領主さんはものすごく強いんです！","ENG":"And the lord of that estate... he's beyond dangerous!","TWN":"領地主人很強呢！"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"엘릭서라는 약물로 자신을 개조했다고요.","JPN":"エリクサーという薬物で体を改造してるんですよ！","ENG":"He modified himself with the Elixir!","TWN":"他用聖水這種藥物改造了自己。"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"흠…… 난 멍멍이한테 승산 없는 선택을 하지 말라고 누누이 가르쳤어.","JPN":"ふーん……私はね、ワンちゃんに勝ち目のない戦いはするなと、普段から教えているの。","ENG":"Hmm... I always told Puppy never to make a losing bet.","TWN":"嗯……我一直教導狗狗不要做沒有勝算的選擇。"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"널 밖으로 내보낸 것이 유일하게 이기는 방법이라 판단한 거겠지.","JPN":"だから、あなたを外に逃がすことが唯一勝てる方法だと判断したんだと思うわ。","ENG":"If she sent you out, she must've decided this was the only way to win.","TWN":"把你送出去是她認為唯一能贏的方法吧。"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하, 하지만…….","JPN":"で、でも……","ENG":"B-but...","TWN":"可，可是……"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"분명 돈 받기 전까진 못 나간다고 했는데요?","JPN":"お金をもらうまでは一歩も動かないと言ったんですよ？","ENG":"She said she wouldn't leave until she got paid.","TWN":"她說過沒收到錢之前不能走。"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"누가 봐도 유언이잖아요, 그거.","JPN":"どう見ても遺言じゃないですか。","ENG":"That's basically a final will...","TWN":"那很明顯是遺言吧。"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"악령을 상대하기 위해선 임기응변에 능해야 해.","JPN":"悪霊の相手をするためには臨機応変に長けていないといけないわ。","ENG":"Exorcists need to think on their feet.","TWN":"想要對付惡靈，就必須善於隨機應變。"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"남몰래 침식 쐐기를 파괴하는 것도 기술이거든.","JPN":"人にバレずに侵食楔を破壊するのも技術が要るのよね。","ENG":"Silently destroying Corrupted Wedges is part of the job, too.","TWN":"悄悄地破壞侵蝕釘也是一門技術。"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그냥 사기꾼이 사기 치려고 연기했다는 말로밖에 안 들리는데요.","JPN":"詐欺師が詐欺のために演技したって話にしか聞こえません。","ENG":"That just sounds like a scammer making up an excuse to lie!","TWN":"聽起來就像是騙子在演戲。"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"제법 보는 눈이 날카롭네.","JPN":"ずいぶんと鋭いのね。","ENG":"Sharp observation.","TWN":"你蠻聰明的嘛。"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"하지만, 이 순간에도 시간은 흐르고 있어.","JPN":"でも、この瞬間も時は流れている。","ENG":"But time is still ticking.","TWN":"但是，現在時間正在流逝。"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L28_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"그리고 지금 움직일 수 있는 건 너 하나뿐이지.","JPN":"そして動けるのはあなただけ。","ENG":"And you're the only one who can act right now.","TWN":"而現在能行動的就只有你一個了。"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"내 말대로만 움직여준다면, 분명 멍멍이를 구할 수 있을 거야.","JPN":"私の言った通りにしてくれれば、きっとワンちゃんを助けられるはずよ。","ENG":"If you follow my instructions, I promise you that you can save her.","TWN":"只要按照我說的去做，一定能救出狗狗。"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……좋아요.","JPN":"……わかりました。","ENG":"...Okay.","TWN":"……好的。"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"불량식품이 괜히 절 보내진 않았겠죠. 믿어볼게요.","JPN":"お菓子さんの判断を信じます。だから、あなたのことも信じてみます。","ENG":"Junk food must have a reason for sending me to you. I'll trust you.","TWN":"垃圾食物不會無緣無故派我來的，我會相信你的。"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"멍멍이보단 고분고분해서 좋네.","JPN":"ワンちゃんよりは大人しくていいわ。","ENG":"You're much more obedient than Puppy.","TWN":"比起狗狗，還是你聽話一點。"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"우리랑 같이 살지 않을래?","JPN":"どう？　私たちと一緒に暮らしてみない？","ENG":"Why not join us?","TWN":"要不要和我們一起生活？"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……생각해 보고요.","JPN":"……考えてみます。","ENG":"...I'll think about it.","TWN":"……我想想。"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"역시 당신이 저택에서 일을 꾸미고 있던 게 분명해.","JPN":"やっぱりあなた、邸宅で何かを企んでいたんだ。","ENG":"You must be behind what's happening in this mansion.","TWN":"果然是你在策劃這些事情的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"흥! 아무튼 맛있는 냄새를 풍긴 당신이 잘못이야!","JPN":"ふん！　とにかく、美味しそうな匂いをさせてるあなたが悪いんです！","ENG":"Hmph! Whatever! You're the one reeking of something delicious, so this is on you!","TWN":"哼！總之都是你散發出美味的香氣，才會惹出麻煩！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아주 달콤하고…… 맛있는 피 냄새가…….","JPN":"とても甘くて……美味しそうな血の匂いが……","ENG":"So sweet... Such an intoxicating scent...","TWN":"好香甜……好美味的血腥味啊……"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"피를 주세요!","JPN":"血をください！","ENG":"Give me blood!","TWN":"請給我血！"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"당신의 달콤한 피를!","JPN":"あなたの甘い血を！","ENG":"I need your sweet blood!","TWN":"你甜美的血！"},"stage":{"bg":"CITY_CENTER3","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"원래 이런 진로 상담도 다 돈을 받아내는 법인데.","JPN":"本当は、こういう進路相談も全部代金を取るんだけど……","ENG":"Counseling sessions like this usually come with a service fee.","TWN":"原本這種職業諮詢都是要收費的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이걸로 나 살려준 빚은 갚았다?","JPN":"これで助けてもらった借りはチャラだからね。","ENG":"Consider your debt paid.","TWN":"這樣我就還清了你救我的恩情了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"주님께 맹세했듯이, 루시아 릿지를 반드시 구하겠습니다.","JPN":"主の御名に誓った通り、ルシア・リッジを必ず助けます。","ENG":"I swore to the Lord that I will save Lucia Ridge.","TWN":"如同向主發誓一樣，我一定會救出露西卡·李奇。"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L12_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그곳에선…… 항상 불량식품의 피를……?","JPN":"そこでは……いつもお菓子さんの血を……？","ENG":"And then... I could have her blood...?","TWN":"在那裡……有垃圾食物的血……？"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"흐, 흐흣…….","JPN":"ふ、ふふつ……","ENG":"Hehe... Hehehe...","TWN":"嗯，嗯哼……"},"stage":{"bg":"MANSION_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"……?","JPN":"……？","ENG":"...?","TWN":"……？"},"stage":{"bg":"MANSION_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"아무튼, 준비는 끝난 것 같네. 출발하도록 해.","JPN":"とにかく、もう準備は済んだようね。行きましょうか。","ENG":"Anyway, it looks like you're ready. Time to go.","TWN":"準備好了，出發吧。"},"stage":{"bg":"MANSION_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"흠흠, 잘 부탁드려요.","JPN":"ごほん……よろしくお願いします。","ENG":"Ahem. I'm counting on you.","TWN":"呃，請多多關照。"},"stage":{"bg":"MANSION_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"저는 뭐가 됐든 불량식품만 구하면 되니까.","JPN":"私はなんとかお菓子さんを救出すればいいですから。","ENG":"As long as I can save Junk food, nothing else matters.","TWN":"我只要找到垃圾食物就行了。"},"stage":{"bg":"MANSION_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"좋아. 나는 딱 한 마디만 참견하고 빠질게.","JPN":"ええ。じゃあ、私はあと一つだけ言って失礼するわ。","ENG":"All right. I'll just say one more thing then get out of your hair.","TWN":"好吧，我就再插一句話就好。"},"stage":{"bg":"MANSION_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"네……? 계속 도와주시려는 거 아니었어요?","JPN":"え……？　この後も力を貸してくださるんじゃなかったんですか？","ENG":"Huh...? Weren't you going to help the whole way through?","TWN":"嗯……？你不是會幫我到最後嗎？"},"stage":{"bg":"MANSION_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L25_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"여기서 더 참견하면 학회장님이 날 꽁꽁 얼려버릴지도 몰라.","JPN":"これ以上口出しを続けたら、学会長が私をカチカチに凍らせてしまうかもしれないの。","ENG":"If I overstep any more, the President might have me frozen solid.","TWN":"再多管閒事的話，學會長可能會把我凍成冰塊。"},"stage":{"bg":"MANSION_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"뭐, 이미 많이 참견한 것 같긴 하지만…….","JPN":"まあ、すでに口出ししすぎた気もしないでもないけど……","ENG":"Though... I might've already pushed my luck.","TWN":"雖然已經插手了很多……"},"stage":{"bg":"MANSION_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"이 정도는 용인해 주길 바랄 수밖에.","JPN":"これぐらいは許してくれることを祈るしかないわね。","ENG":"Guess I'll have to hope she lets it slide.","TWN":"只希望學會長能多包容囉。"},"stage":{"bg":"MANSION_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이, 이제 와서 그런 게 어딨어요!","JPN":"こ、ここまで来てそんなのって！","ENG":"W-what?! You're telling me this now?!","TWN":"怎，怎麼現在才說這些！"},"stage":{"bg":"MANSION_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"앞으로의 일은 네가 어떻게 하느냐에 달렸어.","JPN":"これからはあなた次第よ。","ENG":"The rest is up to you.","TWN":"接下來的事情就看你怎麼做了。"},"stage":{"bg":"MANSION_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"할 수 있지?","JPN":"できるわね？","ENG":"You can handle it, right?","TWN":"你可以吧？"},"stage":{"bg":"MANSION_NIGHT","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……네. 어떻게든 해낼게요.","JPN":"……はあ。まあ、なんとかやってみます。","ENG":"...Yes. I'll figure it out.","TWN":"……嗯，我一定可以的。"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"아, 그런 김에 부탁할 게 있는데…….","JPN":"あ、それと、お願いしたいことがあるんだけど……","ENG":"Oh, and one more thing...","TWN":"啊，順便有件事想拜託你……"},"stage":{"bg":"MANSION_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};